function GridContainer({
  children,
  className,
  direction = "full",
}: {
  children: React.ReactNode;
  className?: string;
  direction?: "full" | "to-left" | "to-right";
}) {
  let topDirection = "";
  let bottomDirection = "";
  switch (direction) {
    case "full":
      topDirection = "before:-left-[100vw]";
      bottomDirection = "after:-left-[100vw]";
      break;
    case "to-left":
      topDirection = "before:right-0";
      bottomDirection = "after:right-0";
      break;
    case "to-right":
      topDirection = "before:left-0";
      bottomDirection = "after:left-0";
      break;
  }

  return (
    <div
      className={clsx(
        className,
        "relative",
        "before:absolute before:top-0 before:h-px before:w-[200vw] before:bg-gray-950/5 dark:before:bg-white/10",
        topDirection,
        "after:absolute after:bottom-0 after:h-px after:w-[200vw] after:bg-gray-950/5 dark:after:bg-white/10",
        bottomDirection,
      )}
    >
      {children}
    </div>
  );
}

async function getTailwindCssFile(cwd: string, configCssFile?: string) {
  // If the existing config has a known CSS file, check it first.
  if (configCssFile) {
    const resolvedPath = path.resolve(cwd, configCssFile)
    if (await fs.pathExists(resolvedPath)) {
      return configCssFile
    }
  }

  const [files, tailwindVersion] = await Promise.all([
    fg.glob(["**/*.css", "**/*.scss"], {
      cwd,
      deep: 5,
      ignore: PROJECT_SHARED_IGNORE,
    }),
    getTailwindVersion(cwd),
  ])

  if (!files.length) {
    return null
  }

  const needle =
    tailwindVersion === "v4" ? `@import "tailwindcss"` : "@tailwind base"
  for (const file of files) {
    const contents = await fs.readFile(path.resolve(cwd, file), "utf8")
    if (
      contents.includes(`@import "tailwindcss"`) ||
      contents.includes(`@import 'tailwindcss'`) ||
      contents.includes(`@tailwind base`)
    ) {
      return file
    }
  }

  return null
}

async function updateCssVars(
  cssVars: z.infer<typeof registryItemCssVarsSchema> | undefined,
  config: Config,
  options: {
    cleanupDefaultNextStyles?: boolean
    overwriteCssVars?: boolean
    silent?: boolean
    tailwindVersion?: TailwindVersion
    tailwindConfig?: z.infer<typeof registryItemTailwindSchema>["config"]
  }
) {
  if (!config.resolvedPaths.tailwindCss || !Object.keys(cssVars ?? {}).length) {
    return
  }

  options = {
    cleanupDefaultNextStyles: false,
    silent: false,
    tailwindVersion: "v3",
    overwriteCssVars: false,
    ...options,
  }
  const cssFilepath = config.resolvedPaths.tailwindCss
  const cssFilepathRelative = path.relative(
    config.resolvedPaths.cwd,
    cssFilepath
  )
  const cssVarsSpinner = spinner(
    `Updating CSS variables in ${highlighter.info(cssFilepathRelative)}`,
    {
      silent: options.silent,
    }
  ).start()
  const raw = await fs.readFile(cssFilepath, "utf8")
  let output = await transformCssVars(raw, cssVars ?? {}, config, {
    cleanupDefaultNextStyles: options.cleanupDefaultNextStyles,
    tailwindVersion: options.tailwindVersion,
    tailwindConfig: options.tailwindConfig,
    overwriteCssVars: options.overwriteCssVars,
  })
  await fs.writeFile(cssFilepath, output, "utf8")
  cssVarsSpinner.succeed()
}

function AccordionTitle(props: AccordionTitleProps) {
  const { arrowIcon: ArrowIcon, flush, isOpen, setOpen } = useAccordionContext();
  const onClick = () => typeof setOpen !== "undefined" && setOpen();

  const provider = useThemeProvider();
  const theme = useResolveTheme(
    [accordionTheme.title, provider.theme?.accordion?.title, props.theme],
    [get(provider.clearTheme, "accordion.title"), props.clearTheme],
    [get(provider.applyTheme, "accordion.title"), props.applyTheme],
  );

  const { as: Heading = "h2", children, className, ...restProps } = resolveProps(props, provider.props?.accordionTitle);

  return (
    <button
      className={twMerge(theme.base, theme.flush[flush ? "on" : "off"], theme.open[isOpen ? "on" : "off"], className)}
      onClick={onClick}
      type="button"
      {...restProps}
    >
      <Heading className={theme.heading} data-testid="flowbite-accordion-heading">
        {children}
      </Heading>
      {ArrowIcon && (
        <ArrowIcon
          aria-hidden
          className={twMerge(theme.arrow.base, theme.arrow.open[isOpen ? "on" : "off"])}
          data-testid="flowbite-accordion-arrow"
        />
      )}
    </button>
  );
}

function MegaMenuDropdown(props: MegaMenuDropdownProps) {
  const [labelledBy, setLabelledBy] = useState<string | undefined>(undefined);

  const provider = useThemeProvider();
  const theme = useResolveTheme(
    [megaMenuTheme.dropdown, provider.theme?.megaMenu?.dropdown, props.theme],
    [get(provider.clearTheme, "megaMenu.dropdown"), props.clearTheme],
    [get(provider.applyTheme, "megaMenu.dropdown"), props.applyTheme],
  );

  const { children, className, toggle, ...restProps } = resolveProps(props, provider.props?.megaMenuDropdown);

  if (toggle) {
    return (
      <Dropdown
        inline
        label={toggle}
        placement="bottom"
        theme={theme.toggle}
        className={twMerge(theme.base, className)}
      >
        {children}
      </Dropdown>
    );
  }

  const id = useId();
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const toggle = ref.current?.closest("nav")?.querySelector('[aria-haspopup="menu"]');
    setLabelledBy(toggle?.id);
  }, []);

  return (
    <div
      aria-labelledby={labelledBy}
      id={id}
      ref={ref}
      role="menu"
      className={twMerge(theme.base, className)}
      {...restProps}
    >
      {children}
    </div>
  );
}

const VideoPlayerView = (props: VideoPlayerViewProps) => {
  const {
    autoPlay,
    className,
    controls,
    height = 300,
    playMode,
    poster,
    showQRCode = true,
    srcDark,
    srcLight,
    width,
  } = props;
  const {resolvedTheme} = useTheme();

  // Default to the light video during SSR (resolvedTheme is undefined until
  // mounted). The mismatch is acceptable because the video tag re-renders
  // immediately after hydration with the correct src.
  const videoSrc = resolvedTheme === "dark" ? srcDark : srcLight;

  return (
    <div className={cn("flex flex-col items-end gap-4", className)}>
      {!!showQRCode && <QRPreviewPopover {...pickNativeQRTarget(props)} />}

      <VideoPlayer
        autoPlay={autoPlay}
        controls={controls}
        height={height}
        playMode={playMode}
        poster={poster}
        src={videoSrc}
        width={width}
      />
    </div>
  );
};

function load() {
  if (id === 'tailwindcss') {
    return {
      path: 'virtual:tailwindcss/index.css',
      base,
      content: assets.css.index,
    }
  } else if (
    id === 'tailwindcss/preflight' ||
    id === 'tailwindcss/preflight.css' ||
    id === './preflight.css'
  ) {
    return {
      path: 'virtual:tailwindcss/preflight.css',
      base,
      content: assets.css.preflight,
    }
  } else if (
    id === 'tailwindcss/theme' ||
    id === 'tailwindcss/theme.css' ||
    id === './theme.css'
  ) {
    return {
      path: 'virtual:tailwindcss/theme.css',
      base,
      content: assets.css.theme,
    }
  } else if (
    id === 'tailwindcss/utilities' ||
    id === 'tailwindcss/utilities.css' ||
    id === './utilities.css'
  ) {
    return {
      path: 'virtual:tailwindcss/utilities.css',
      base,
      content: assets.css.utilities,
    }
  }

  throw new Error(`The browser build does not support @import for "${id}"`)
}

async function compileAndExtractStyles(styleContent, defaultTheme, theme) {
  const compiledContent = (
    await compile(
      `
    @layer theme{${defaultTheme}${theme}}
    @layer wrapperStart{${styleContent}}
    @layer wrapperEnd
  `,
      {
        // Polyfills:
        // None = 0,
        // AtProperty = 1,
        // ColorMix = 2,
        // All = 3
        polyfills: 1, // AtProperty only, excludes ColorMix
      },
    )
  ).build([])

  const startIndex = compiledContent.indexOf("@layer wrapperStart")
  const endIndex = compiledContent.indexOf("@layer wrapperEnd")

  if (startIndex === -1 || endIndex === -1) {
    throw new Error("Failed to find wrapper layers in compiled content")
  }

  const openingBraceIndex = compiledContent.indexOf("{", startIndex)
  const closingBraceIndex = compiledContent.lastIndexOf("}", endIndex)

  if (
    openingBraceIndex === -1 ||
    closingBraceIndex === -1 ||
    openingBraceIndex >= closingBraceIndex
  ) {
    throw new Error("Invalid wrapper structure in compiled content")
  }

  return compiledContent.substring(openingBraceIndex + 1, closingBraceIndex).trim()
}

function* migrate(rawCandidate: string) {
  for (let candidate of designSystem.parseCandidate(rawCandidate)) {
    // Create a base candidate string from the candidate.
    // E.g.: `hover:blur!` -> `blur`
    let base = baseCandidate(candidate)
    let baseCandidateString = designSystem.printCandidate(base)

    // Find the new base candidate string. `blur` -> `blur-sm`
    let newBaseCandidateString = LEGACY_CLASS_MAP.get(baseCandidateString)
    if (!newBaseCandidateString) continue

    // Parse the new base candidate string into an actual candidate AST.
    let [newBaseCandidate] = designSystem.parseCandidate(newBaseCandidateString)
    if (!newBaseCandidate) continue

    // Re-apply the variants and important flag from the original candidate.
    // E.g.: `hover:blur!` -> `blur` -> `blur-sm` -> `hover:blur-sm!`
    let newCandidate = cloneCandidate(newBaseCandidate) as Candidate
    newCandidate.variants = candidate.variants
    newCandidate.important = candidate.important

    yield [
      newCandidate,
      THEME_KEYS.get(baseCandidateString),
      THEME_KEYS.get(newBaseCandidateString),
    ] as const
  }
}

function Panel({
  className,
  numbered,
  children,
  ...props
}: {
  className?: string;
  numbered?: boolean;
  children?: React.ReactNode;
  [key: string]: any;
}) {
  return (
    // We *want* the sticky positioning because that means the scrollbar handles
    // appear over the tab bar instead of under it. However, this presents a
    // problem. We are no longer able to use `flex-col-reverse` for the terminal
    // because it puts the tab bar at the bottom of the container. Wrapping an
    // element around everything fixes it but breaks horizontal sticky
    // positioning — vertical keeps working.
    //
    // As a workaround we use a client component to scroll things instead
    <AnchoredToBottom
      {...props}
      enabled={true}
      className={clsx(
        "isolate",
        "flex flex-col overflow-hidden rounded-lg bg-white/10 dark:bg-white/5",
        "inset-ring inset-ring-white/5",
        numbered && "with-line-numbers",
        className,
      )}
    >
      {children}
    </AnchoredToBottom>
  );
}

function candidatesToAst(classes: string[]): AstNode[][] {
  let result: AstNode[][] = []

  for (let className of classes) {
    let wasValid = true

    let { astNodes } = compileCandidates([className], designSystem, {
      onInvalidCandidate() {
        wasValid = false
      },
    })

    if (utilitiesSrc) {
      walk(astNodes, (node) => {
        // We do this conditionally to preserve source locations from both
        // `@utility` and `@custom-variant`. Even though generated nodes are
        // cached this should be fine because `utilitiesNode.src` should not
        // change without a full rebuild which destroys the cache.
        node.src ??= utilitiesSrc
        return WalkAction.Continue
      })
    }

    // Disable all polyfills to not unnecessarily pollute IntelliSense output
    astNodes = optimizeAst(astNodes, designSystem, Polyfills.None)

    result.push(wasValid ? astNodes : [])
  }

  return result
}

function migrateImport(): Plugin {
  async function migrate(root: Root) {
    let file = root.source?.input.file
    if (!file) return

    let promises: Promise<void>[] = []
    root.walkAtRules('import', (rule) => {
      try {
        let [firstParam, ...rest] = segment(rule.params, ' ')

        let params = parseImportParams(ValueParser.parse(firstParam))
        if (!params) return

        let isRelative = params.uri[0] === '.'
        let hasCssExtension = params.uri.endsWith('.css')

        if (isRelative && hasCssExtension) {
          return
        }

        let fullPath = resolve(dirname(file), params.uri)
        if (!hasCssExtension) fullPath += '.css'

        promises.push(
          fs.stat(fullPath).then(() => {
            let ext = hasCssExtension ? '' : '.css'
            let path = isRelative ? params.uri : `./${params.uri}`
            rule.params = [`'${path}${ext}'`, ...rest].join(' ')
          }),
        )
      } catch {
        // When an error occurs while parsing the `@import` statement, we skip
        // the import. This will happen in cases where you import an external
        // URL.
      }
    })

    await Promise.allSettled(promises)
  }

  return {
    postcssPlugin: '@tailwindcss/upgrade/migrate-import',
    OnceExit: migrate,
  }
}

